const q = $.input.question;
const staticTerms = 'GitHub API documentation docs.github.com';
return { query: q + ' ' + staticTerms };

const results = $.steps.searchDocs.response.results || [];
const docs = results.map((r, i) => ({
  index: i + 1,
  title: r.title || 'Untitled',
  url: r.url || '',
  text: (r.text || '').slice(0, 1500)
})).filter(d => d.url.length > 0).slice(0, 3);
return { docs, count: docs.length };

const docs = $.steps.extractTopResults.output.docs || [];
const iterations = $.steps.scrapeDocs.response.iterations || [];
let context = '';
docs.forEach((d, i) => {
  context += '--- DOC ' + d.index + ': ' + d.title + ' ---\n';
  context += 'URL: ' + d.url + '\n';
  if (iterations[i] && iterations[i].scrapeOne && iterations[i].scrapeOne.response) {
    const s = iterations[i].scrapeOne.response;
    const content = s.data ? (s.data.markdown || s.data.content || s.data.text || '') : (typeof s === 'string' ? s : JSON.stringify(s));
    context += content.slice(0, 4000) + '\n';
  } else {
    context += d.text + '\n';
  }
  context += '\n';
});
return { context: context.slice(0, 20000) };

const ctx = $.steps.compileContext.output.context;
const question = $.input.question;
let prompt = 'You are a GitHub API expert. Answer the following question using the documentation context provided.

';
prompt += 'QUESTION: ' + question + '

';
prompt += 'DOCUMENTATION CONTEXT:
' + ctx + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Provide a clear, detailed answer
';
prompt += '- Include code examples where appropriate
';
prompt += '- Cite the documentation sources
';
prompt += '- If the docs are insufficient, say so clearly

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "answer": "detailed answer with code examples",
';
prompt += '  "endpoint": "relevant API endpoint if applicable",
';
prompt += '  "method": "HTTP method (GET/POST/etc)",
';
prompt += '  "codeExample": "curl or code example",
';
prompt += '  "sources": ["url1", "url2"],
';
prompt += '  "confidence": "high|medium|low"
';
prompt += '}';
return { prompt };

let raw = $.steps.aiAnswer.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, endpoint: '', method: '', codeExample: '', sources: [], confidence: 'medium' }; }

const ai = $.steps.parseAI.output;
const q = $.input.question;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'GitHub API Q&A', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Q:* ' + q } });
blocks.push({ type: 'divider' });

const answer = (ai.answer || 'No answer found').slice(0, 2000);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*A:* ' + answer } });

if (ai.endpoint) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Endpoint:* `' + (ai.method || 'GET') + ' ' + ai.endpoint + '`' } });
}

if (ai.codeExample) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Example:*\n```' + ai.codeExample.slice(0, 800) + '```' } });
}

const sources = ai.sources || [];
if (sources.length > 0) {
  const srcText = sources.map(s => '<' + s + '|link>').join(' | ');
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Sources: ' + srcText + ' | Confidence: ' + (ai.confidence || 'medium') }] });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa + Firecrawl + Claude AI' }] });

const fallback = 'GitHub API Q&A: ' + q.slice(0, 60);
return { blocks, fallback };
